import React from "react";
import styles from "./product-presentation.module.css";

interface PresentationProps {
  imgSrc: string;
}

const ProductPresentation: React.FC<PresentationProps> = ({ imgSrc }) => {
  console.log("imgSrc:", imgSrc); 
  return (
    <div className={styles.wrapper_product_presentation}>
      <img
        className={styles.product_image}
        src={imgSrc}
        width={540}
        height={433}
        alt="candle"
      />
      <div className={styles.desc}>
        <p>"All hand-made with natural soy wax, Candleaf is made for your pleasure
          moments."</p>
        <p className={styles.desc2}>"🚚 FREE SHIPPING"</p>
      </div>
    </div>
  );
};

export default ProductPresentation;
